function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function s(v) { return v == null ? '' : String(v).trim(); }
function stripDataPrefix(value) { return s(value).replace(/^data:.*;base64,/i, ''); }
function extensionFromMimeType(mimeType) {
  if (/webp/i.test(mimeType)) return 'webp';
  if (/jpe?g/i.test(mimeType)) return 'jpg';
  return 'png';
}
function findDirectImageUrl(root) {
  const candidates = [
    root?.image_url, root?.imageUrl, root?.url,
    root?.data?.image_url, root?.data?.imageUrl, root?.data?.url,
    root?.result?.image_url, root?.result?.url,
  ];
  for (const value of candidates) {
    const url = s(value);
    if (/^https?:\/\//i.test(url) && !/\.(mp4|mov|m3u8)(\?|$)/i.test(url)) return url;
  }
  const data = Array.isArray(root?.data) ? root.data : [];
  for (const item of data) {
    const url = s(item?.url || item?.image_url || item?.imageUrl);
    if (/^https?:\/\//i.test(url) && !/\.(mp4|mov|m3u8)(\?|$)/i.test(url)) return url;
  }
  return '';
}
function collectInlineImages(value, depth = 0) {
  if (depth > 6 || value == null) return [];
  if (Array.isArray(value)) return value.flatMap((item) => collectInlineImages(item, depth + 1));
  if (typeof value !== 'object') return [];

  const obj = value;
  const inline = obj.inline_data || obj.inlineData;
  if (inline && typeof inline === 'object' && s(inline.data)) {
    return [{ data: stripDataPrefix(inline.data), mimeType: s(inline.mime_type || inline.mimeType || 'image/png') }];
  }
  const b64 = obj.b64_json || obj.b64Json || obj.image_base64 || obj.imageBase64 || obj.base64 || obj.base64_json || obj.base64Json;
  if (s(b64)) return [{ data: stripDataPrefix(b64), mimeType: s(obj.mime_type || obj.mimeType || 'image/png') }];

  return Object.values(obj).flatMap((item) => collectInlineImages(item, depth + 1));
}

const root = unwrapRoot($json || {});
const inlineImage = collectInlineImages(root)[0] || null;

if (!inlineImage) {
  const sourceImageUrl = findDirectImageUrl(root);
  if (!sourceImageUrl) throw new Error('未从生图响应中解析到图片 URL 或 inline/base64 图片，请检查上游 API 输出。');
  return {
    json: {
      source_image_url: sourceImageUrl,
      needs_download: true
    }
  };
}

const mimeType = inlineImage.mimeType || 'image/png';
const extension = extensionFromMimeType(mimeType);
const fileName = 'storyboard-image-' + Date.now() + '.' + extension;

return {
  json: {
    source_image_url: '',
    needs_download: false,
    mimeType,
    fileName
  },
  binary: {
    data: {
      data: stripDataPrefix(inlineImage.data),
      mimeType,
      fileName
    }
  }
};

const current = $input.item.json || {};
if (current.image_url) {
  return { json: { image_url: current.image_url } };
}
const uploadResp = current;
const imageUrl = uploadResp.url || uploadResp.image_url || uploadResp.data?.url || '';
return { json: { image_url: imageUrl } };

const items = $input.all();
const results = [];

for (const item of items) {
  const body = item.json.body || item.json;

  function s(v) { return v == null ? '' : String(v).trim(); }
  function toList(v) {
    if (Array.isArray(v)) return v.flatMap(toList);
    if (v && typeof v === 'object') return toList(v.url || v.image_url || v.imageUrl || v.src || v.href);
    if (typeof v === 'string') {
      const t = v.trim();
      if (!t) return [];
      try {
        const parsed = JSON.parse(t);
        const list = toList(parsed);
        return list.length ? list : [t];
      } catch {
        return [t];
      }
    }
    return [];
  }
  function unique(vals) {
    const seen = new Set();
    const out = [];
    for (const v of vals) {
      const t = s(v);
      if (!t || seen.has(t)) continue;
      seen.add(t);
      out.push(t);
    }
    return out;
  }
  function clampRef(v, fb) {
    const n = Number(v);
    if (!Number.isFinite(n)) return fb;
    return Math.min(Math.max(Math.floor(n), 0), 8);
  }
  function normKey(v) { return s(v || 'image2'); }
  function normProv(mk, cap) {
    const p = s(cap.provider).toLowerCase();
    const n = mk.toLowerCase();
    if (p === 'image2' || n === 'image2' || n === 'gpt-image-2-all' || n.includes('gpt-image-2')) return 'image2';
    return 'gemini-image';
  }
  function pickApi(mk, p) {
    if (p === 'image2') return 'gpt-image-2-all';
    const key = s(mk);
    const map = {
      nanoBananapro: 'gemini-3-pro-image-preview',
      nanoBananaPro: 'gemini-3-pro-image-preview',
      'nano-banana-pro': 'gemini-3-pro-image-preview',
      nanoBanana2: 'gemini-3.1-flash-image-preview',
      'nano-banana-2': 'gemini-3.1-flash-image-preview',
      'gemini-3-pro-image-preview': 'gemini-3-pro-image-preview',
      'gemini-3.1-flash-image-preview': 'gemini-3.1-flash-image-preview'
    };
    return map[key] || key || 'gemini-3-pro-image-preview';
  }
  function normalizeAspectRatio(value) {
    const raw = s(value).toLowerCase();
    if (!raw) return '';
    if (['portrait', 'vertical', '竖屏', '竖版', '手机竖屏'].includes(raw)) return '9:16';
    if (['landscape', 'horizontal', '横屏', '横版'].includes(raw)) return '16:9';
    if (['square', '方图', '1/1', '1:1'].includes(raw)) return '1:1';
    if (raw === '2/3' || raw === '2:3') return '9:16';
    if (raw === '3/2' || raw === '3:2') return '16:9';
    if (raw === '3/4' || raw === '3:4') return '3:4';
    if (raw === '4/3' || raw === '4:3') return '4:3';
