  }
  function aspectRatioFromSize(size) {
    const match = s(size).match(/^(\d{3,5})\s*x\s*(\d{3,5})$/i);
    if (!match) return '';
    const w = Number(match[1]);
    const h = Number(match[2]);
    if (!Number.isFinite(w) || !Number.isFinite(h) || w <= 0 || h <= 0) return '';
