    const explicit = text.match(/(?:^|[^\d])(9\s*[:/]\s*16|16\s*[:/]\s*9|2\s*[:/]\s*3|3\s*[:/]\s*2|3\s*[:/]\s*4|4\s*[:/]\s*3|1\s*[:/]\s*1)(?:[^\d]|$)/);
    return explicit ? normalizeAspectRatio(explicit[1].replace(/\s+/g, '')) : '';
  }
  function normalizeImage2Size(size, aspectRatio) {
    const raw = s(size).toLowerCase().replace(/\s+/g, '');
    if (/^\d{3,5}x\d{3,5}$/.test(raw)) return raw;
    if (aspectRatio === '16:9' || aspectRatio === '4:3') return '1536x1024';
    if (aspectRatio === '9:16' || aspectRatio === '3:4') return '1024x1536';
    return '1024x1024';
  }

  const prompt = s(body.prompt || body.raw_prompt);
  if (!prompt) throw new Error('缺少 prompt');

  const cap = body.model_capabilities && typeof body.model_capabilities === 'object' ? body.model_capabilities : {};
  const mk = normKey(body.model || body.requested_model);
  const prov = normProv(mk, cap);
  const fbLimit = prov === 'image2' ? 8 : 5;
  const maxRef = clampRef(cap.max_reference_images ?? body.max_reference_images ?? fbLimit, fbLimit);

  const numUrls = Array.from({ length: 8 }, (_, i) => body['reference_image_url_' + (i + 1)]);
  const refUrls = unique([
