const items = $input.all();
if (!items || items.length === 0) throw new Error('没有接收到数据');

const baseData = items[0].json._baseData;
if (!baseData || typeof baseData !== 'object') throw new Error('缺少标准化后的 _baseData');

const provider = baseData.provider;
let requestUrl = '';
let requestBody = {};
let refCount = 0;

function s(v) { return v == null ? '' : String(v).trim(); }
