  const key = binary.data ? 'data' : Object.keys(binary)[0];
  if (!key) return null;
  const meta = binary[key] || {};
  let data = '';
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, key);
    data = buffer.toString('base64');
  } catch (error) {
    data = s(meta.data).replace(/^data:.*;base64,/i, '');
  }
  if (!data) return null;
  return {
    mime_type: s(meta.mimeType || meta.mime_type || 'image/jpeg'),
    data
