if (provider === 'image2') {
  requestUrl = 'https://yunwu.ai/v1/images/generations';
  const imageUrls = Array.isArray(baseData.reference_image_urls) ? baseData.reference_image_urls.filter(Boolean) : [];
  requestBody = {
    model: baseData.api_model,
    size: baseData.image2_size || '1024x1024',
    n: 1,
    prompt: baseData.promptText
  };
  if (imageUrls.length === 1) requestBody.image = imageUrls[0];
  if (imageUrls.length > 1) requestBody.image = imageUrls;
  refCount = imageUrls.length;
