  requestUrl = 'https://yunwu.ai/v1beta/models/' + baseData.api_model + ':generateContent';
  const parts = [{ text: baseData.promptText }];
  for (let i = 0; i < items.length; i += 1) {
    const inlineData = await binaryToInlineData.call(this, i, items[i]);
    if (!inlineData) continue;
    refCount += 1;
    parts.push({ text: 'Reference image ' + refCount });
    parts.push({ inline_data: inlineData });
  }
  requestBody = {
    contents: [{ role: 'user', parts }],
    generationConfig: {
      responseModalities: ['IMAGE'],
      response_modalities: ['IMAGE'],
